script.text:

/* <flatten type="Javascript"> */
function load$Grid(g) {
  g.add_onResponseComplete(on$GridContractBalance$ResponseComplete);
  g.add_commandEvent(on$GridContractBalance$ExecuteCommand);
}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$GridContractBalance$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridContractBalance$ResponseComplete);} catch (ex) {}
}
function on$GridContractBalance$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'ContractBalanceImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$GridContractBalance$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}

function show$Form(g, c) {
  (g._authorize == 1) && (!g._denyNew) ? g.showForm(c) : $message.show(g._denyMessage ? g._denyMessage : $df.getResources(g._language, "Message.NotAccess"));
}
/* </flatten> */

      &DowloadScript;
